.link{
  color: var(--green-2);
  font-weight: 800;
  text-decoration: underline;
  text-decoration-color: rgba(167,157,117,.65);
}

/* Footer */
.footer{
  margin: 18px 0 26px;
  padding: 16px 0;
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap: 12px;
  color: var(--muted);
}
.footer__links{display:flex; gap:14px}
.footer__links a{color: var(--green-2); font-weight: 800}

/* Modal */
.modal{
  position: fixed;
  inset: 0;
  display:none;
  align-items:center;
  justify-content:center;
  padding: 18px;
  z-index: 100;
}
.modal[aria-hidden="false"]{display:flex}
.modal__backdrop{
  position:absolute; inset:0;
  background: rgba(0,0,0,.45);
}
.modal__card{
  position: relative;
  width: min(760px, 100%);
  background:#fff;
  border-radius: var(--radius);
  border: 1px solid rgba(62,66,36,.18);
  box-shadow: 0 24px 60px rgba(0,0,0,.22);
  overflow:hidden;
}
.modal__card--small{width:min(520px,100%)}
.modal__card::before{
  content:"";
  position:absolute;
  top:0; left:0; right:0;
  height:2px;
  background: linear-gradient(90deg, var(--gold), transparent);
}
.modal__head{
  padding: 14px 16px;
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap: 12px;
  border-bottom: 1px solid rgba(62,66,36,.10);
}
.modal__title{
  margin:0;
  font-family:"Playfair Display", serif;
  letter-spacing:.02em;
}
.iconbtn{
  border:none;
  background: transparent;
  cursor:pointer;
  font-size: 18px;
  padding: 10px 12px;
  border-radius: 12px;
}
.iconbtn:hover{background: rgba(71,75,40,.06)}
.modal form{padding: 16px}
.grid2{
  display:grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
}
.grid2__full{grid-column: 1 / -1}
.modal__actions{
  display:flex;
  justify-content:flex-end;
  gap: 10px;
  padding: 12px 16px 16px;
  border-top: 1px solid rgba(62,66,36,.10);
}
.confirm__text{padding: 14px 16px; color: var(--text);}

.title{margin:0; font-family:"Playfair Display", serif;}
.muted{color: var(--muted)}

/* Responsive */
@media (max-width: 980px){
  .panel__row{grid-template-columns: 1fr; align-items:stretch}

}
